module RefModule (
    input [15:0] data_in, // 4 elements of 4 bits each
    output reg [15:0] data_out // sorted 4 elements of 4 bits each
);
    integer i, j;
    reg [3:0] unused_temp [0:3]; // temporary storage for sorting

    always @* begin
        // Load input data into temporary array
        for (i = 0; i < 4; i = i + 1) begin
            unused_temp[i] = data_in[i*4 +: 4];
        end

        // Bubble sort algorithm
        for (i = 0; i < 3; i = i + 1) begin
            for (j = 0; j < 3 - i; j = j + 1) begin
                if (unused_temp[j] > unused_temp[j + 1]) begin
                    // Swap
                    unused_temp[j] = unused_temp[j] ^ unused_temp[j + 1];
                    unused_temp[j + 1] = unused_temp[j] ^ unused_temp[j + 1];
                    unused_temp[j] = unused_temp[j] ^ unused_temp[j + 1];
                end
            end
        end

        // Load sorted data into output
        data_out = {unused_temp[3], unused_temp[2], unused_temp[1], unused_temp[0]};
    end
endmodule
